mapper.sql:
/* 물류진행요청관리 */ WITH SJD AS ( SELECT M.* , C.CLNT_NM , C.BIZ_ADDR||DECODE(C.BIZ_ADDR_DTL,NULL,'',' '||C.BIZ_ADDR_DTL) AS CLNT_ADDR , (SELECT FN_CM05M01_CD_TO_NM(M.CLNT_PJT) FROM DUAL) AS CLNT_PJT_NM FROM TB_CR02M01 M INNER JOIN TB_BM02M01 AS C ON M.ORDRS_CLNT_CD = C.CLNT_CD --INNER JOIN TB_CR02D02 AS X ON X.CO_CD = M.CO_CD AND X.ORDRS_NO = M.ORDRS_NO--수주상세 WHERE 1=1 AND M.CO_CD = #{coCd}
AND M.ORDRS_NO LIKE '%'||#{ordrsNo}||'%'
AND M.ORDRS_DT >= #{pblicteDtFr} AND M.ORDRS_DT <= #{pblicteDtTo}
AND C.CLNT_NM LIKE '%'||#{clntNm}||'%'
AND M.CLNT_PJT LIKE '%'||#{clntPjt}||'%'
AND M.ORDRS_DIV = #{ordrsDiv}
AND M.CTRT_NM LIKE '%'||#{ctrtNm}||'%'
) , LGIST_LIST AS (SELECT LGIST_NO , COUNT(*) AS SALES_CD_CNT , LISTAGG(SALES_CD, ' , ') WITHIN GROUP (ORDER BY SALES_CD ASC) AS SALES_CD_LIST FROM TB_CR11D01 WHERE 1=1 GROUP BY LGIST_NO ) , SCR AS ( SELECT TO_CHAR(A.ORDRS_CLNT_CD)||T.ORDRS_NO AS UPPER_CD , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS LOWER_CD , T.CO_CD , T.ORDRS_NO , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS TITLE , A.ORDRS_CLNT_CD , A.CLNT_NM AS ORDRS_CLNT_NM , A.CLNT_ADDR , T.CLNT_PJT , A.CLNT_PJT_NM , T.FILE_TRGT_KEY , T.LGIST_NO , T.PBLICTE_DT , T.REQ_ID , (SELECT FN_CM06M01_ID_TO_NM(T.REQ_ID) FROM DUAL) AS REQ_ID_NM , T.PART_NO , T.REQ_FX_DT , (SELECT FN_CM05M01_CD_TO_NM(T.CLAS_DIV) FROM DUAL) AS CLAS_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.TRNS_DIV) FROM DUAL) AS TRNS_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_TRNS_AREA_DIV) FROM DUAL) AS DMS_TRNS_AREA_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_SEND_CND_DIV) FROM DUAL) AS DMS_SEND_CND_DIV_NM , T.DMS_SEND_CND_DIV_ETC , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_PACK_KIND_DIV) FROM DUAL) AS DMS_PACK_KIND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_TRNS_AREA_DIV) FROM DUAL) AS OVS_TRNS_AREA_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_SEND_CND_DIV) FROM DUAL) AS OVS_SEND_CND_DIV_NM , T.OVS_SEND_CND_DIV_ETC , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_PACK_KIND_DIV) FROM DUAL) AS OVS_PACK_KIND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_TRNS_AREA_DIV ELSE OVS_TRNS_AREA_DIV END) FROM DUAL) AS TRNS_AREA_DIV_NM , CASE WHEN INSTR(DMS_SEND_CND_DIV,'99') = 13 THEN DMS_SEND_CND_DIV_ETC WHEN INSTR(OVS_SEND_CND_DIV,'99') = 13 THEN OVS_SEND_CND_DIV_ETC ELSE FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_SEND_CND_DIV ELSE OVS_SEND_CND_DIV END) END AS SEND_CND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_PACK_KIND_DIV ELSE OVS_PACK_KIND_DIV END) FROM DUAL) AS PACK_KIND_DIV_NM , T.STA_PLACE , T.STA_ADDR , T.STA_CHRG_ID , (SELECT FN_CM06M01_ID_TO_NM(T.STA_CHRG_ID) FROM DUAL) AS STA_CHRG_ID_NM , T.ARVL_PLACE , T.ARVL_ADDR , T.ARVL_CHRG_CONT , T.PRDLST_CONT , T.PRD_AMT , T.WIDTH_SIZE , T.VRTICL_SIZE , T.HEIGHT_SIZE , T.FRMLC_BEFORE_WT , T.FRMLC_AFTER_WT , T.SHIPMNT_DT , T.HOPE_ARVL_DT , T.LGIST_RMK , T.TODO_DIV1_CODE_ID , T.TODO_DIV2_CODE_ID , L.SALES_CD_LIST , L.SALES_CD_CNT , T.LGIST_COMPL_YN , TO_CHAR(T.LGIST_COMPL_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS LGIST_COMPL_DTTM , T.LGIST_COMPL_ID , FN_CM06M01_ID_TO_NM(T.LGIST_COMPL_ID) AS LGIST_COMPL_ID_NM , T.LGIST_COMPL_RMK , T.STA_CHRG_CONT FROM TB_CR11M01 T LEFT OUTER JOIN LGIST_LIST L ON T.LGIST_NO = L.LGIST_NO INNER JOIN SJD A ON T.CO_CD = A.CO_CD AND T.ORDRS_NO = A.ORDRS_NO WHERE T.CO_CD = #{coCd} ------------------------------------------------------------------------------------------------- -- 요청자, 분류구분, 운송구분, PART_NO 조건은 여기... ------------------------------------------------------------------------------------------------- ) , CO_ADDR AS ( SELECT BIZ_ADDR||DECODE(BIZ_ADDR_DTL,NULL,'',' '||BIZ_ADDR_DTL) AS BIZ_ADDR FROM TB_BM02M01 WHERE ROWNUM = 1 AND CLNT_CD = ( SELECT CODE_ETC FROM TB_CM05M01 WHERE USE_YN = 'Y' AND CODE_KIND = 'CO' AND CODE_ID = #{coCd} ) ) SELECT (SELECT FN_CM05M01_CD_TO_NM(T.CO_CD) FROM DUAL) AS CO_NM , T.* , (SELECT CASE WHEN ( COUNT(A.TODO_KEY) = SUM(DECODE(NVL(A.SANCTN_STTUS, 'N'), 'N', 0, 'Y', 1) ) ) THEN 'Y' ELSE TO_CHAR( SUM(DECODE(NVL(A.SANCTN_STTUS, 'N'), 'N', 0, 'Y', 1) ) ) END TODO_YN FROM TB_WB20M03 A WHERE A.TODO_NO = T.LGIST_NO AND A.TODO_DIV1_CODE_ID = 'TODODIV20') AS APP_STATUS , ( SELECT BIZ_ADDR FROM CO_ADDR ) AS CO_ADDR FROM ( SELECT DISTINCT '' AS UPPER_CD , TO_CHAR(X.ORDRS_CLNT_CD)||X.ORDRS_NO AS LOWER_CD , X.CO_CD AS CO_CD , X.ORDRS_NO AS ORDRS_NO , X.ORDRS_NO AS TITLE , X.ORDRS_CLNT_CD AS ORDRS_CLNT_CD , X.CLNT_NM AS ORDRS_CLNT_NM , X.CLNT_PJT AS CLNT_PJT , X.CLNT_PJT_NM AS CLNT_PJT_NM , '' AS FILE_TRGT_KEY , '' AS LGIST_NO , '' AS PBLICTE_DT , '' AS REQ_ID , '' AS REQ_ID_NM , '' AS PART_NO , '' AS REQ_FX_DT , '' AS CLAS_DIV_NM , '' AS TRNS_DIV_NM , '' AS DMS_TRNS_AREA_DIV_NM , '' AS DMS_SEND_CND_DIV_NM , '' AS DMS_SEND_CND_DIV_ETC , '' AS DMS_PACK_KIND_DIV_NM , '' AS OVS_TRNS_AREA_DIV_NM , '' AS OVS_SEND_CND_DIV_NM , '' AS OVS_SEND_CND_DIV_ETC , '' AS OVS_PACK_KIND_DIV_NM , '' AS TRNS_AREA_DIV_NM , '' AS SEND_CND_DIV_NM , '' AS PACK_KIND_DIV_NM , '' AS STA_PLACE , '' AS STA_ADDR , '' AS STA_CHRG_ID , '' AS STA_CHRG_ID_NM , '' AS ARVL_PLACE , '' AS ARVL_ADDR , '' AS ARVL_CHRG_CONT , '' AS PRDLST_CONT , '' AS PRD_AMT , '' AS WIDTH_SIZE , '' AS VRTICL_SIZE , '' AS HEIGHT_SIZE , '' AS FRMLC_BEFORE_WT , '' AS FRMLC_AFTER_WT , '' AS SHIPMNT_DT , '' AS HOPE_ARVL_DT , '' AS LGIST_RMK , '' AS TODO_DIV1_CODE_ID , '' AS TODO_DIV2_CODE_ID , '' AS SALES_CD_LIST , '' AS SALES_CD_CNT , '' AS LGIST_COMPL_YN , '' AS LGIST_COMPL_DTTM , '' AS LGIST_COMPL_ID , '' AS LGIST_COMPL_ID_NM , '' AS LGIST_COMPL_RMK , CLNT_ADDR AS CLNT_ADDR , '' AS STA_CHRG_CONT FROM SJD X WHERE 1=1 UNION ALL SELECT R.UPPER_CD , R.LOWER_CD , R.CO_CD , R.ORDRS_NO , R.TITLE , R.ORDRS_CLNT_CD , R.ORDRS_CLNT_NM , R.CLNT_PJT , R.CLNT_PJT_NM , R.FILE_TRGT_KEY , R.LGIST_NO , R.PBLICTE_DT , R.REQ_ID , R.REQ_ID_NM , R.PART_NO , R.REQ_FX_DT , R.CLAS_DIV_NM , R.TRNS_DIV_NM , R.DMS_TRNS_AREA_DIV_NM , R.DMS_SEND_CND_DIV_NM , R.DMS_SEND_CND_DIV_ETC , R.DMS_PACK_KIND_DIV_NM , R.OVS_TRNS_AREA_DIV_NM , R.OVS_SEND_CND_DIV_NM , R.OVS_SEND_CND_DIV_ETC , R.OVS_PACK_KIND_DIV_NM , R.TRNS_AREA_DIV_NM , R.SEND_CND_DIV_NM , R.PACK_KIND_DIV_NM , R.STA_PLACE , R.STA_ADDR , R.STA_CHRG_ID , R.STA_CHRG_ID_NM , R.ARVL_PLACE , R.ARVL_ADDR , R.ARVL_CHRG_CONT , R.PRDLST_CONT , R.PRD_AMT , R.WIDTH_SIZE , R.VRTICL_SIZE , R.HEIGHT_SIZE , R.FRMLC_BEFORE_WT , R.FRMLC_AFTER_WT , R.SHIPMNT_DT , R.HOPE_ARVL_DT , R.LGIST_RMK , R.TODO_DIV1_CODE_ID , R.TODO_DIV2_CODE_ID , R.SALES_CD_LIST , R.SALES_CD_CNT , R.LGIST_COMPL_YN , R.LGIST_COMPL_DTTM , R.LGIST_COMPL_ID , R.LGIST_COMPL_ID_NM , R.LGIST_COMPL_RMK , R.CLNT_ADDR , R.STA_CHRG_CONT FROM SCR R WHERE 1=1 ) T ORDER BY T.ORDRS_CLNT_NM, T.ORDRS_NO DESC

/* 물류진행요청관리 */ WITH SJD AS ( SELECT M.* , C.CLNT_NM , C.BIZ_ADDR||DECODE(C.BIZ_ADDR_DTL,NULL,'',' '||C.BIZ_ADDR_DTL) AS CLNT_ADDR , (SELECT FN_CM05M01_CD_TO_NM(M.CLNT_PJT) FROM DUAL) AS CLNT_PJT_NM FROM TB_CR02M01 M INNER JOIN TB_BM02M01 AS C ON M.ORDRS_CLNT_CD = C.CLNT_CD --INNER JOIN TB_CR02D02 AS X ON X.CO_CD = M.CO_CD AND X.ORDRS_NO = M.ORDRS_NO--수주상세 WHERE 1=1 AND M.CO_CD = #{coCd} AND M.ORDRS_DT >= #{pblicteDtFr} AND M.ORDRS_DT <= #{pblicteDtTo}
AND C.CLNT_NM LIKE '%'||#{clntNm}||'%'
AND M.CLNT_PJT LIKE '%'||#{clntPjt}||'%'
AND M.ORDRS_DIV = #{ordrsDiv}
AND M.ORDRS_NO LIKE '%'||#{ordrsNo}||'%'
AND M.CTRT_NM LIKE '%'||#{ctrtNm}||'%'
) , LGIST_LIST AS (SELECT LGIST_NO , COUNT(*) AS SALES_CD_CNT , LISTAGG(SALES_CD, ' , ') WITHIN GROUP (ORDER BY SALES_CD ASC) AS SALES_CD_LIST FROM TB_CR11D01 WHERE 1=1 GROUP BY LGIST_NO ) , SCR AS ( SELECT TO_CHAR(A.ORDRS_CLNT_CD)||T.ORDRS_NO AS UPPER_CD , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS LOWER_CD , T.CO_CD , T.ORDRS_NO , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS TITLE , A.ORDRS_CLNT_CD , A.CLNT_NM AS ORDRS_CLNT_NM , A.CLNT_ADDR , T.CLNT_PJT , A.CLNT_PJT_NM , T.FILE_TRGT_KEY , T.LGIST_NO , T.PBLICTE_DT , T.REQ_ID , (SELECT FN_CM06M01_ID_TO_NM(T.REQ_ID) FROM DUAL) AS REQ_ID_NM , T.PART_NO , T.REQ_FX_DT , (SELECT FN_CM05M01_CD_TO_NM(T.CLAS_DIV) FROM DUAL) AS CLAS_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.TRNS_DIV) FROM DUAL) AS TRNS_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_TRNS_AREA_DIV) FROM DUAL) AS DMS_TRNS_AREA_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_SEND_CND_DIV) FROM DUAL) AS DMS_SEND_CND_DIV_NM , T.DMS_SEND_CND_DIV_ETC , (SELECT FN_CM05M01_CD_TO_NM(T.DMS_PACK_KIND_DIV) FROM DUAL) AS DMS_PACK_KIND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_TRNS_AREA_DIV) FROM DUAL) AS OVS_TRNS_AREA_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_SEND_CND_DIV) FROM DUAL) AS OVS_SEND_CND_DIV_NM , T.OVS_SEND_CND_DIV_ETC , (SELECT FN_CM05M01_CD_TO_NM(T.OVS_PACK_KIND_DIV) FROM DUAL) AS OVS_PACK_KIND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_TRNS_AREA_DIV ELSE OVS_TRNS_AREA_DIV END) FROM DUAL) AS TRNS_AREA_DIV_NM , CASE WHEN INSTR(DMS_SEND_CND_DIV,'99') = 13 THEN DMS_SEND_CND_DIV_ETC WHEN INSTR(OVS_SEND_CND_DIV,'99') = 13 THEN OVS_SEND_CND_DIV_ETC ELSE FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_SEND_CND_DIV ELSE OVS_SEND_CND_DIV END) END AS SEND_CND_DIV_NM , (SELECT FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_PACK_KIND_DIV ELSE OVS_PACK_KIND_DIV END) FROM DUAL) AS PACK_KIND_DIV_NM , T.STA_PLACE , T.STA_ADDR , T.STA_CHRG_ID , (SELECT FN_CM06M01_ID_TO_NM(T.STA_CHRG_ID) FROM DUAL) AS STA_CHRG_ID_NM , T.ARVL_PLACE , T.ARVL_ADDR , T.ARVL_CHRG_CONT , T.PRDLST_CONT , T.PRD_AMT , T.WIDTH_SIZE , T.VRTICL_SIZE , T.HEIGHT_SIZE , T.FRMLC_BEFORE_WT , T.FRMLC_AFTER_WT , T.SHIPMNT_DT , T.HOPE_ARVL_DT , T.LGIST_RMK , T.TODO_DIV1_CODE_ID , T.TODO_DIV2_CODE_ID , L.SALES_CD_LIST , L.SALES_CD_CNT , T.STA_CHRG_CONT FROM TB_CR11M01 T LEFT OUTER JOIN LGIST_LIST L ON T.LGIST_NO = L.LGIST_NO INNER JOIN SJD A ON T.CO_CD = A.CO_CD AND T.ORDRS_NO = A.ORDRS_NO WHERE T.CO_CD = #{coCd} ------------------------------------------------------------------------------------------------- -- 요청자, 분류구분, 운송구분, PART_NO 조건은 여기... ------------------------------------------------------------------------------------------------- ) , CO_ADDR AS ( SELECT BIZ_ADDR||DECODE(BIZ_ADDR_DTL,NULL,'',' '||BIZ_ADDR_DTL) AS BIZ_ADDR FROM TB_BM02M01 WHERE ROWNUM = 1 AND CLNT_CD = ( SELECT CODE_ETC FROM TB_CM05M01 WHERE USE_YN = 'Y' AND CODE_KIND = 'CO' AND CODE_ID = #{coCd} ) ) , APP_STATUS_LIST AS ( SELECT A.CO_CD , B.TODO_DIV1_CODE_ID , B.TODO_DIV2_CODE_ID , CASE WHEN SUM(CASE WHEN B.TODO_CF_DT IS NOT NULL THEN 1 ELSE 0 END) = SUM(CASE WHEN A.USE_YN = 'Y' THEN 1 ELSE 0 END) THEN 'APP9' WHEN SUM(CASE WHEN B.TODO_CF_DT IS NOT NULL THEN 1 ELSE 0 END) > 0 THEN 'APP1' ELSE 'APP0' END AS APP_STATUS FROM TB_BM13M01 A JOIN TB_WB20M03 B ON A.CO_CD = B.CO_CD AND A.APP_DIV = B.TODO_DIV1_CODE_ID AND A.APP_ID = B.TODO_ID WHERE A.APP_DIV = 'APPDIV03' GROUP BY A.CO_CD , B.TODO_DIV1_CODE_ID , B.TODO_DIV2_CODE_ID ) SELECT (SELECT FN_CM05M01_CD_TO_NM(T.CO_CD) FROM DUAL) AS CO_NM , T.* , CASE WHEN T.FILE_TRGT_KEY IS NOT NULL THEN NVL(AP.APP_STATUS, 'APP0') END AS APP_STATUS , ( SELECT BIZ_ADDR FROM CO_ADDR ) AS CO_ADDR FROM ( SELECT DISTINCT '' AS UPPER_CD , TO_CHAR(X.ORDRS_CLNT_CD)||X.ORDRS_NO AS LOWER_CD , X.CO_CD AS CO_CD , X.ORDRS_NO AS ORDRS_NO , X.ORDRS_NO AS TITLE , X.ORDRS_CLNT_CD AS ORDRS_CLNT_CD , X.CLNT_NM AS ORDRS_CLNT_NM , X.CLNT_PJT AS CLNT_PJT , X.CLNT_PJT_NM AS CLNT_PJT_NM , '' AS FILE_TRGT_KEY , '' AS LGIST_NO , '' AS PBLICTE_DT , '' AS REQ_ID , '' AS REQ_ID_NM , '' AS PART_NO , '' AS REQ_FX_DT , '' AS CLAS_DIV_NM , '' AS TRNS_DIV_NM , '' AS DMS_TRNS_AREA_DIV_NM , '' AS DMS_SEND_CND_DIV_NM , '' AS DMS_SEND_CND_DIV_ETC , '' AS DMS_PACK_KIND_DIV_NM , '' AS OVS_TRNS_AREA_DIV_NM , '' AS OVS_SEND_CND_DIV_NM , '' AS OVS_SEND_CND_DIV_ETC , '' AS OVS_PACK_KIND_DIV_NM , '' AS TRNS_AREA_DIV_NM , '' AS SEND_CND_DIV_NM , '' AS PACK_KIND_DIV_NM , '' AS STA_PLACE , '' AS STA_ADDR , '' AS STA_CHRG_ID , '' AS STA_CHRG_ID_NM , '' AS ARVL_PLACE , '' AS ARVL_ADDR , '' AS ARVL_CHRG_CONT , '' AS PRDLST_CONT , '' AS PRD_AMT , '' AS WIDTH_SIZE , '' AS VRTICL_SIZE , '' AS HEIGHT_SIZE , '' AS FRMLC_BEFORE_WT , '' AS FRMLC_AFTER_WT , '' AS SHIPMNT_DT , '' AS HOPE_ARVL_DT , '' AS LGIST_RMK , '' AS TODO_DIV1_CODE_ID , '' AS TODO_DIV2_CODE_ID , '' AS SALES_CD_LIST , '' AS SALES_CD_CNT , CLNT_ADDR AS CLNT_ADDR , '' AS STA_CHRG_CONT FROM SJD X WHERE 1=1 UNION ALL SELECT R.UPPER_CD , R.LOWER_CD , R.CO_CD , R.ORDRS_NO , R.TITLE , R.ORDRS_CLNT_CD , R.ORDRS_CLNT_NM , R.CLNT_PJT , R.CLNT_PJT_NM , R.FILE_TRGT_KEY , R.LGIST_NO , R.PBLICTE_DT , R.REQ_ID , R.REQ_ID_NM , R.PART_NO , R.REQ_FX_DT , R.CLAS_DIV_NM , R.TRNS_DIV_NM , R.DMS_TRNS_AREA_DIV_NM , R.DMS_SEND_CND_DIV_NM , R.DMS_SEND_CND_DIV_ETC , R.DMS_PACK_KIND_DIV_NM , R.OVS_TRNS_AREA_DIV_NM , R.OVS_SEND_CND_DIV_NM , R.OVS_SEND_CND_DIV_ETC , R.OVS_PACK_KIND_DIV_NM , R.TRNS_AREA_DIV_NM , R.SEND_CND_DIV_NM , R.PACK_KIND_DIV_NM , R.STA_PLACE , R.STA_ADDR , R.STA_CHRG_ID , R.STA_CHRG_ID_NM , R.ARVL_PLACE , R.ARVL_ADDR , R.ARVL_CHRG_CONT , R.PRDLST_CONT , R.PRD_AMT , R.WIDTH_SIZE , R.VRTICL_SIZE , R.HEIGHT_SIZE , R.FRMLC_BEFORE_WT , R.FRMLC_AFTER_WT , R.SHIPMNT_DT , R.HOPE_ARVL_DT , R.LGIST_RMK , R.TODO_DIV1_CODE_ID , R.TODO_DIV2_CODE_ID , R.SALES_CD_LIST , R.SALES_CD_CNT , R.CLNT_ADDR , R.STA_CHRG_CONT FROM SCR R WHERE 1=1 ) T LEFT OUTER JOIN APP_STATUS_LIST AP ON T.CO_CD = AP.CO_CD AND T.TODO_DIV1_CODE_ID = AP.TODO_DIV1_CODE_ID AND T.TODO_DIV2_CODE_ID = AP.TODO_DIV2_CODE_ID

WITH APP_STATUS_LIST AS ( SELECT A.CO_CD , B.TODO_DIV1_CODE_ID , B.TODO_DIV2_CODE_ID , CASE WHEN SUM(CASE WHEN B.TODO_CF_DT IS NOT NULL THEN 1 ELSE 0 END) = SUM(CASE WHEN A.USE_YN = 'Y' THEN 1 ELSE 0 END) THEN 'APP9' WHEN SUM(CASE WHEN B.TODO_CF_DT IS NOT NULL THEN 1 ELSE 0 END) > 0 THEN 'APP1' ELSE 'APP0' END AS APP_STATUS FROM TB_BM13M01 A JOIN TB_WB20M03 B ON A.CO_CD = B.CO_CD AND A.APP_DIV = B.TODO_DIV1_CODE_ID AND A.APP_ID = B.TODO_ID WHERE A.APP_DIV = 'APPDIV03' GROUP BY A.CO_CD, B.TODO_DIV1_CODE_ID, B.TODO_DIV2_CODE_ID ) , APP_TODO_LIST AS ( SELECT A.CO_CD , B.TODO_DIV1_CODE_ID , B.TODO_DIV2_CODE_ID , A.APP_SEQ , B.TODO_ID , FN_CM06M01_ID_TO_NM(B.TODO_ID) AS TODO_ID_NM , DECODE(B.TODO_CF_DT,NULL,'N','Y') AS TODO_CF_YN , X.DEPT_NM , (SELECT LEVEL_NM FROM TB_CM07M01 WHERE LEVEL_CD=X.LEVEL_CD) AS LEVEL_NM FROM TB_BM13M01 A JOIN TB_WB20M03 B ON A.CO_CD = B.CO_CD AND A.APP_DIV = B.TODO_DIV1_CODE_ID AND A.APP_ID = B.TODO_ID LEFT OUTER JOIN ( SELECT BB.ID , BB.NAME , BB.LEVEL_CD , BB.EMAIL , BB.TEL_NO , BB.OFF_TEL_NO , BB.FAX_NO , CC.DEPT_NM FROM TB_CM06M01 BB INNER JOIN TB_CM04M01 CC ON(BB.DEPT_ID=CC.DEPT_ID) WHERE 1 = 1 ) X ON(B.TODO_ID=X.ID) WHERE A.APP_DIV = 'APPDIV03' ) SELECT LEVEL AS LEV , FN_CM05M01_CD_TO_NM(T.CO_CD) CO_NM , T.* , FN_CM06M01_ID_TO_NM(T.STA_CHRG_ID) AS STA_CHRG_ID_NM , (SELECT LISTAGG(SALES_CD, ' , ') WITHIN GROUP (ORDER BY SALES_CD ASC) FROM TB_CR11D01 WHERE LGIST_NO = T.LGIST_NO) AS SALES_CD_LIST , CASE WHEN LGIST_NO IS NULL THEN '' ELSE (SELECT COUNT(*) FROM TB_CR11D01 WHERE LGIST_NO = T.LGIST_NO) END AS SALES_CD_CNT , REGEXP_REPLACE(SYS_CONNECT_BY_PATH(T.LOWER_CD, ' -> '), '^\s+\-\>\s+', '') AS PATH , CASE WHEN T.FILE_TRGT_KEY IS NOT NULL THEN NVL(AP.APP_STATUS, 'APP0') END AS APP_STATUS , ( SELECT BIZ_ADDR||DECODE(BIZ_ADDR_DTL,NULL,'',' '||BIZ_ADDR_DTL) AS BIZ_ADDR FROM TB_BM02M01 WHERE CLNT_CD = ( SELECT CODE_ETC FROM TB_CM05M01 WHERE USE_YN = 'Y' AND CODE_KIND = 'CO' AND CODE_ID = #{coCd} ) ) AS CO_ADDR , ( SELECT BIZ_ADDR||DECODE(BIZ_ADDR_DTL,NULL,'',' '||BIZ_ADDR_DTL) AS BIZ_ADDR FROM TB_BM02M01 WHERE CLNT_CD = T.ORDRS_CLNT_CD ) AS CLNT_ADDR FROM ( /* top -> 회사 -> 고객사 */ SELECT DISTINCT 'top' AS UPPER_CD , TO_CHAR(Y.ORDRS_CLNT_CD) LOWER_CD , X.CO_CD , '' AS ORDRS_NO , A.CLNT_NM AS TITLE , Y.ORDRS_CLNT_CD , A.CLNT_NM AS ORDRS_CLNT_NM , '' AS CLNT_PJT , '' AS CLNT_PJT_NM , '' AS FILE_TRGT_KEY , '' AS LGIST_NO , '' AS PBLICTE_DT , '' AS REQ_ID , '' AS REQ_ID_NM , '' AS PART_NO , '' AS REQ_FX_DT , '' AS CLAS_DIV_NM , '' AS TRNS_DIV_NM , '' AS DMS_TRNS_AREA_DIV_NM , '' AS DMS_SEND_CND_DIV_NM , '' AS DMS_SEND_CND_DIV_ETC , '' AS DMS_PACK_KIND_DIV_NM , '' AS OVS_TRNS_AREA_DIV_NM , '' AS OVS_SEND_CND_DIV_NM , '' AS OVS_SEND_CND_DIV_ETC , '' AS OVS_PACK_KIND_DIV_NM , '' AS TRNS_AREA_DIV_NM , '' AS SEND_CND_DIV_NM , '' AS PACK_KIND_DIV_NM , '' AS STA_PLACE , '' AS STA_ADDR , '' AS STA_CHRG_ID , '' AS ARVL_PLACE , '' AS ARVL_ADDR , '' AS ARVL_CHRG_CONT , '' AS PRDLST_CONT , '' AS PRD_AMT , '' AS WIDTH_SIZE , '' AS VRTICL_SIZE , '' AS HEIGHT_SIZE , '' AS FRMLC_BEFORE_WT , '' AS FRMLC_AFTER_WT , '' AS SHIPMNT_DT , '' AS HOPE_ARVL_DT , '' AS LGIST_RMK , '' AS TODO_DIV1_CODE_ID , '' AS TODO_DIV2_CODE_ID FROM TB_CR02D02 X INNER JOIN TB_CR02M01 Y ON X.CO_CD = Y.CO_CD AND X.ORDRS_NO = Y.ORDRS_NO LEFT OUTER JOIN TB_BM02M01 A ON Y.ORDRS_CLNT_CD = A.CLNT_CD WHERE X.CO_CD = #{coCd}
AND A.CLNT_NM LIKE '%'||#{clntNm}||'%'
UNION ALL /* top -> 고객사 -> 수주번호 */ SELECT DISTINCT TO_CHAR(Y.ORDRS_CLNT_CD) UPPER_CD , X.ORDRS_NO LOWER_CD , X.CO_CD , X.ORDRS_NO , X.ORDRS_NO AS TITLE , Y.ORDRS_CLNT_CD , A.CLNT_NM AS ORDRS_CLNT_NM , Y.CLNT_PJT , FN_CM05M01_CD_TO_NM(Y.CLNT_PJT) AS CLNT_PJT_NM , '' AS FILE_TRGT_KEY , '' AS LGIST_NO , '' AS PBLICTE_DT , '' AS REQ_ID , '' AS REQ_ID_NM , '' AS PART_NO , '' AS REQ_FX_DT , '' AS CLAS_DIV_NM , '' AS TRNS_DIV_NM , '' AS DMS_TRNS_AREA_DIV_NM , '' AS DMS_SEND_CND_DIV_NM , '' AS DMS_SEND_CND_DIV_ETC , '' AS DMS_PACK_KIND_DIV_NM , '' AS OVS_TRNS_AREA_DIV_NM , '' AS OVS_SEND_CND_DIV_NM , '' AS OVS_SEND_CND_DIV_ETC , '' AS OVS_PACK_KIND_DIV_NM , '' AS TRNS_AREA_DIV_NM , '' AS SEND_CND_DIV_NM , '' AS PACK_KIND_DIV_NM , '' AS STA_PLACE , '' AS STA_ADDR , '' AS STA_CHRG_ID , '' AS ARVL_PLACE , '' AS ARVL_ADDR , '' AS ARVL_CHRG_CONT , '' AS PRDLST_CONT , '' AS PRD_AMT , '' AS WIDTH_SIZE , '' AS VRTICL_SIZE , '' AS HEIGHT_SIZE , '' AS FRMLC_BEFORE_WT , '' AS FRMLC_AFTER_WT , '' AS SHIPMNT_DT , '' AS HOPE_ARVL_DT , '' AS LGIST_RMK , '' AS TODO_DIV1_CODE_ID , '' AS TODO_DIV2_CODE_ID FROM TB_CR02D02 X INNER JOIN TB_CR02M01 Y ON X.CO_CD = Y.CO_CD AND X.ORDRS_NO = Y.ORDRS_NO LEFT OUTER JOIN TB_BM02M01 A ON Y.ORDRS_CLNT_CD = A.CLNT_CD WHERE X.CO_CD = #{coCd}
AND A.CLNT_NM LIKE '%'||#{clntNm}||'%'
AND Y.CLNT_PJT LIKE '%'||#{clntPjt}||'%'
UNION ALL /* top -> 고객사 -> 수주번호 -> 물류번호 */ SELECT T.ORDRS_NO AS UPPER_CD , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS LOWER_CD , T.CO_CD , T.ORDRS_NO , T.ORDRS_NO||'-'||TRIM(TO_CHAR(ROW_NUMBER() OVER(PARTITION BY T.ORDRS_NO ORDER BY T.ORDRS_NO, T.FILE_TRGT_KEY),'0000')) AS TITLE , A.ORDRS_CLNT_CD , B.CLNT_NM AS ORDRS_CLNT_NM , T.CLNT_PJT , FN_CM05M01_CD_TO_NM(T.CLNT_PJT) AS CLNT_PJT_NM , T.FILE_TRGT_KEY , T.LGIST_NO , T.PBLICTE_DT , T.REQ_ID , U.NAME AS REQ_ID_NM , T.PART_NO , T.REQ_FX_DT , FN_CM05M01_CD_TO_NM(T.CLAS_DIV) AS CLAS_DIV_NM , FN_CM05M01_CD_TO_NM(T.TRNS_DIV) AS TRNS_DIV_NM , FN_CM05M01_CD_TO_NM(T.DMS_TRNS_AREA_DIV) AS DMS_TRNS_AREA_DIV_NM , FN_CM05M01_CD_TO_NM(T.DMS_SEND_CND_DIV) AS DMS_SEND_CND_DIV_NM , T.DMS_SEND_CND_DIV_ETC , FN_CM05M01_CD_TO_NM(T.DMS_PACK_KIND_DIV) AS DMS_PACK_KIND_DIV_NM , FN_CM05M01_CD_TO_NM(T.OVS_TRNS_AREA_DIV) AS OVS_TRNS_AREA_DIV_NM , FN_CM05M01_CD_TO_NM(T.OVS_SEND_CND_DIV) AS OVS_SEND_CND_DIV_NM , T.OVS_SEND_CND_DIV_ETC , FN_CM05M01_CD_TO_NM(T.OVS_PACK_KIND_DIV) AS OVS_PACK_KIND_DIV_NM , FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_TRNS_AREA_DIV ELSE OVS_TRNS_AREA_DIV END) AS TRNS_AREA_DIV_NM , CASE WHEN INSTR(DMS_SEND_CND_DIV,'99') = 13 THEN DMS_SEND_CND_DIV_ETC WHEN INSTR(OVS_SEND_CND_DIV,'99') = 13 THEN OVS_SEND_CND_DIV_ETC ELSE FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_SEND_CND_DIV ELSE OVS_SEND_CND_DIV END) END AS SEND_CND_DIV_NM , FN_CM05M01_CD_TO_NM(CASE WHEN TRNS_DIV = 'LGISTDIV0301' THEN DMS_PACK_KIND_DIV ELSE OVS_PACK_KIND_DIV END) AS PACK_KIND_DIV_NM , T.STA_PLACE , T.STA_ADDR , T.STA_CHRG_ID , T.ARVL_PLACE , T.ARVL_ADDR , T.ARVL_CHRG_CONT , T.PRDLST_CONT , T.PRD_AMT , T.WIDTH_SIZE , T.VRTICL_SIZE , T.HEIGHT_SIZE , T.FRMLC_BEFORE_WT , T.FRMLC_AFTER_WT , T.SHIPMNT_DT , T.HOPE_ARVL_DT , T.LGIST_RMK , T.TODO_DIV1_CODE_ID , T.TODO_DIV2_CODE_ID , T.LGIST_COMPL_YN , TO_CHAR(T.LGIST_COMPL_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS LGIST_COMPL_DTTM , T.LGIST_COMPL_ID , FN_CM06M01_ID_TO_NM(T.LGIST_COMPL_ID) AS LGIST_COMPL_ID_NM , T.LGIST_COMPL_RMK FROM TB_CR11M01 T LEFT OUTER JOIN TB_CR02M01 A ON T.CO_CD = A.CO_CD AND T.ORDRS_NO = A.ORDRS_NO LEFT OUTER JOIN TB_BM02M01 B ON A.ORDRS_CLNT_CD = B.CLNT_CD LEFT OUTER JOIN TB_CM06M01 U ON T.REQ_ID = U.ID WHERE T.CO_CD = #{coCd} AND T.PBLICTE_DT >= #{pblicteDtFr} AND T.PBLICTE_DT <= #{pblicteDtTo}
AND U.NAME LIKE '%'||#{reqIdNm}||'%'
AND B.CLNT_NM LIKE '%'||#{clntNm}||'%'
AND T.CLNT_PJT LIKE '%'||#{clntPjt}||'%'
AND T.CLAS_DIV = #{clasDiv}
AND T.TRNS_DIV = #{trnsDiv}
AND T.PART_NO LIKE '%'||#{partNo}||'%'
) T LEFT OUTER JOIN APP_STATUS_LIST AP ON T.CO_CD = AP.CO_CD AND T.TODO_DIV1_CODE_ID = AP.TODO_DIV1_CODE_ID AND T.TODO_DIV2_CODE_ID = AP.TODO_DIV2_CODE_ID START WITH UPPER_CD = 'top' CONNECT BY PRIOR LOWER_CD = UPPER_CD ORDER BY PATH

