SELECT * FROM ( SELECT C.ORDRS_CLNT_CD, T.PBLICTE_DT, T.CLAS_DIV, FN_CM05M01_CD_TO_NM(T.CLAS_DIV) AS CLAS_DIV_NM, T.TRNS_DIV, FN_CM05M01_CD_TO_NM(T.TRNS_DIV) AS TRNS_DIV_NM, T.DMS_TRNS_AREA_DIV, T.DMS_SEND_CND_DIV, T.DMS_SEND_CND_DIV_ETC, T.DMS_PACK_KIND_DIV, T.OVS_TRNS_AREA_DIV, T.OVS_SEND_CND_DIV, T.OVS_SEND_CND_DIV_ETC, T.OVS_PACK_KIND_DIV, T.STA_PLACE, T.STA_ADDR, T.STA_CHRG_ID, T.ARVL_PLACE, T.ARVL_ADDR, T.ARVL_CHRG_CONT, ROW_NUMBER() OVER ( PARTITION BY C.ORDRS_CLNT_CD, /* 주소가 다르면 다른 그룹 -> 목록에 그대로 남음 */ NVL(TRIM(T.STA_ADDR), ' '), NVL(TRIM(T.ARVL_ADDR), ' '), /* 필요 시 장소까지 포함(주소가 같아도 장소명이 다른 케이스 분리) */ NVL(TRIM(T.STA_PLACE), ' '), NVL(TRIM(T.ARVL_PLACE), ' ') /* “물류정보까지 동일해야 중복”이면 아래 라인들을 추가 , NVL(TRIM(T.TRNS_DIV), ' ') , NVL(TRIM(T.DMS_TRNS_AREA_DIV), ' ') , NVL(TRIM(T.DMS_SEND_CND_DIV), ' ') , NVL(TRIM(T.DMS_SEND_CND_DIV_ETC), ' ') , NVL(TRIM(T.DMS_PACK_KIND_DIV), ' ') , NVL(TRIM(T.OVS_TRNS_AREA_DIV), ' ') , NVL(TRIM(T.OVS_SEND_CND_DIV), ' ') , NVL(TRIM(T.OVS_SEND_CND_DIV_ETC), ' ') , NVL(TRIM(T.OVS_PACK_KIND_DIV), ' ') */ ORDER BY T.PBLICTE_DT DESC, T.LGIST_NO DESC ) AS RN FROM TB_CR11M01 T JOIN TB_CR02M01 C ON C.CO_CD = T.CO_CD AND C.ORDRS_NO = T.ORDRS_NO WHERE T.CO_CD = #{coCd}
AND C.ORDRS_CLNT_CD = #{ordrsClntCd}
) WHERE RN = 1 ORDER BY PBLICTE_DT DESC

